
import {computed, defineComponent} from "vue";
import LanguageDropdown from "@/components/languageDropdown/LanguageDropdown.vue";
import projectModule from "@/store/project";

export default defineComponent({
  name: "Header",
  components: {
    LanguageDropdown
  },
  setup() {
    const menuData = [
      {
        title: "про нас"
      },
      {
        title: "розклад"
      },
      {
        title: "ціни"
      },
      {
        title: "запитання"
      },
      {
        title: "контакти"
      },

    ]

    window.addEventListener("scroll", function () {
      const header = document.querySelector('header')
      header?.classList.toggle(
        "sticky",
        window.scrollY > 0
      );
      const logo = document.querySelector('img')

      window.scrollY > 0
        ? logo!.src = require("../../assets/images/logo-black.svg")
        : logo!.src = require("../../assets/images/logo.svg")
    });

    const languages = computed(() => projectModule.languages)
    const currentLanguageKey = computed(() => projectModule.currentLanguage)
    const onSelectLanguage = () => console.log('select')

    return {
      menuData,
      languages,
      currentLanguageKey,
      onSelectLanguage
    }
  }
});
