    Swiper,
    SwiperSlide,
  },
  props: {
    items: {
      type: Object,
      required: true
    },
    initIndex: {
      type: Number,
      required: false,
      default: 0
    },
  },
  setup() {
    const currentIndex = ref(1)
    const getCurrentPerson = (index: number) => {
      return index % 2 === 0
        ? "Person 1"
        : "Person 2"
    }

    const test = (value: any) => {
      const p = new Proxy(value, {});
      currentIndex.value = value.activeIndex + 1
      console.log('test', value.activeIndex)
    }

    return {
      getCurrentPerson,
      test,
      currentIndex
    }
  }
})
